import {applyMiddleware, combineReducers, compose, createStore} from "redux";
import profileReducer from "./profile-reducer";
import dialogsReducer from "./dialogs-reducer";
import sidebarReducer from "./sidebar-reducer";
import usersReducer from "./users-reducer";
import authReducer from "./auth-reducer";
import thunkMiddleware from 'redux-thunk';
import { reducer as formReducer } from 'redux-form'
import appReducer from "./app-reducer";


//Склеиваем редьюсеры и представляем что это стэйт 3 основных ветки берем
let reducers = combineReducers({
    profilePage: profileReducer,
    messagesPage: dialogsReducer,
    sidebar: sidebarReducer,
    usersPage: usersReducer,
    auth: authReducer,
    form: formReducer,
    app: appReducer
});

//Вариант создания store с расширением ReduxDevTools
const composeEnhancers = window.__REDUX_DEVTOOLS_EXTENSION_COMPOSE__ || compose;
const store = createStore(reducers, composeEnhancers(applyMiddleware(thunkMiddleware)));


//создаем сторе и отдаем закомбайненные редьюсеры стору. Вариант без расширения для хрома
//без ReduxDevTools
// let store = createStore(reducers, applyMiddleware(thunkMiddleware));

//глобальное сохранение объекта
window.__store__ = store;

export default store;
